/**
 * safeHtml — XSS-safe HTML construction for UI panels.
 *
 * ## Why this exists
 *
 * Using `innerHTML` with plain template literals trains developers to treat HTML
 * string composition as normal, making it easy to accidentally interpolate a
 * dynamic value (robot name, event title, LLM output) without escaping it.
 * One unescaped `${value}` = stored XSS.
 *
 * ## Usage
 *
 * ### `safeHtml` tagged template — for HTML with dynamic values
 *
 * All interpolated values are automatically HTML-escaped:
 *
 * ```typescript
 * import { safeHtml } from '@ui/utils/safeHtml';
 *
 * el.innerHTML = safeHtml`<div class="title">${event.title}</div>`;
 * el.innerHTML = safeHtml`<span>${robotName} at (${x}, ${y})</span>`;
 * ```
 *
 * The return type is `SafeHtml` (a branded string), not plain `string`. This
 * lets TypeScript flag any attempt to assign a raw `string` to `innerHTML` via
 * a lint rule in future.
 *
 * ### Static HTML with no interpolation — OK as-is
 *
 * Plain template literals with **no interpolation** are safe:
 *
 * ```typescript
 * el.innerHTML = `<span style="color:#7090e0;">⚙ Settings</span>`;  // ✓ safe
 * ```
 *
 * ### CSS-only interpolation — OK as-is
 *
 * Interpolating only into `style="..."` values (colours, dimensions, etc.) is
 * safe because style values cannot execute scripts:
 *
 * ```typescript
 * el.innerHTML = `<div style="color:${color};">${label}</div>`;  // only safe if label is escaped
 * ```
 *
 * Note: if any non-style value is also interpolated, the **whole template**
 * must use `safeHtml`.
 *
 * ## Anti-patterns to avoid
 *
 * ```typescript
 * // ✗ BAD — message may contain LLM output or sim data with < > & characters
 * el.innerHTML = `<div>${message}</div>`;
 *
 * // ✓ GOOD — values are auto-escaped
 * el.innerHTML = safeHtml`<div>${message}</div>`;
 * ```
 *
 * ## Escaping policy
 *
 * The escaper converts: `&` `<` `>` `"` `'`
 * This covers all HTML injection vectors in element text content and attribute values.
 */

declare const SafeHtmlBrand: unique symbol;

/** A string that has been through safeHtml escaping. Assignable to innerHTML. */
export type SafeHtml = string & { readonly [SafeHtmlBrand]: true };

/** Escape a value for safe inclusion in HTML text content or a quoted attribute. */
export function escapeHtml(value: unknown): string {
  return String(value)
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#39;');
}

/**
 * Tagged template that auto-escapes all interpolated values.
 *
 * Static string parts (the template structure) pass through unchanged;
 * interpolated values are HTML-escaped. Returns a `SafeHtml` branded type.
 *
 * @example
 * el.innerHTML = safeHtml`<strong>${event.title}</strong>`;
 */
export function safeHtml(
  strings: TemplateStringsArray,
  ...values: unknown[]
): SafeHtml {
  let result = '';
  for (let i = 0; i < strings.length; i++) {
    result += strings[i];
    if (i < values.length) {
      result += escapeHtml(values[i]);
    }
  }
  return result as SafeHtml;
}

/**
 * Cast a trusted static HTML string to `SafeHtml` without escaping.
 *
 * Use **only** for literal string constants where you control all content —
 * never for any value that could come from user input, sim state, or an API.
 *
 * @example
 * const icon = trustedHtml('<span>&#9883;</span>');
 */
export function trustedHtml(html: string): SafeHtml {
  return html as SafeHtml;
}
